INSERT IGNORE INTO `t_hospital` (`id`, `name`, `level`, `address`, `phone`, `intro`, `image`, `province`, `city`, `department_count`, `doctor_count`, `follow_count`, `status`, `create_time`, `update_time`) VALUES
(1, '北京协和医院', '三级甲等', '北京市东城区东单北大街1号', '010-12345678', '北京协和医院是中国顶尖的综合性医院之一，拥有悠久的历史和卓越的医疗水平。', 'img/hospital_100001977.jpg', '北京', '北京', 35, 800, 12500, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(2, '上海瑞金医院', '三级甲等', '上海市黄浦区瑞金二路197号', '021-87654321', '上海交通大学医学院附属瑞金医院是一所大型综合性医院，医疗技术先进。', 'img/hospital_14616536073112.jpg', '上海', '上海', 32, 750, 10800, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(3, '广州中山医院', '三级甲等', '广州市越秀区东风西路195号', '020-23456789', '中山大学附属第一医院是华南地区著名的综合性医院，医疗实力雄厚。', 'img/hospital_16043929044175.jpg', '广东', '广州', 30, 680, 9200, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(4, '杭州浙一医院', '三级甲等', '杭州市上城区庆春路79号', '0571-98765432', '浙江大学医学院附属第一医院是浙江省规模最大的综合性医院。', 'img/hospital_16195932543164.png', '浙江', '杭州', 28, 620, 8500, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(5, '武汉同济医院', '三级甲等', '武汉市硚口区解放大道1095号', '027-83665555', '华中科技大学同济医学院附属同济医院是中部地区重要的医疗中心。', 'img/hospital_100001977.jpg', '湖北', '武汉', 33, 720, 9600, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(6, '成都华西医院', '三级甲等', '成都市武侯区国学巷37号', '028-85422114', '四川大学华西医院是西南地区首屈一指的综合性医院。', 'img/hospital_14616536073112.jpg', '四川', '成都', 34, 780, 11200, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00');
