(4, '陈美玲', 2, '主治医师', 14, 4, 'img/doctor-female-doc.jpg', '13800138004', '陈美玲主治医师，肾内科专家。', '肾病综合征、肾炎、尿毒症', 2100, 4.85, 1200, 1, 60.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(5, '张伟民', 1, '主任医师', 15, 5, 'img/doctor-male-doc.jpg', '13800138005', '张伟民主任医师，内分泌科专家。', '糖尿病、甲状腺疾病、肥胖症', 3800, 4.90, 1900, 2, 90.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(6, '刘芳华', 2, '副主任医师', 16, 6, 'img/doctor-female-doc.jpg', '13800138006', '刘芳华副主任医师，血液科专家。', '白血病、贫血、血小板减少', 2800, 4.86, 1500, 2, 80.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(7, '赵强', 1, '主任医师', 21, 1, 'img/doctor-male-doc.jpg', '13800138007', '赵强主任医师，普外科专家。', '阑尾炎、胆囊炎、胆结石、胃癌', 4200, 4.89, 1700, 1, 100.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(8, '孙丽华', 2, '副主任医师', 22, 2, 'img/doctor-female-doc.jpg', '13800138008', '孙丽华副主任医师，骨科专家。', '关节置换、骨折、颈椎病', 3500, 4.87, 1600, 1, 90.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(9, '马晓峰', 1, '主任医师', 11, 5, 'img/doctor-male-doc.jpg', '13800138009', '马晓峰主任医师，心外科专家。', '心脏瓣膜病、冠心病搭桥、先心病', 2900, 4.93, 1400, 1, 150.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(10, '周婷婷', 2, '副主任医师', 31, 3, 'img/doctor-female-doc.jpg', '13800138010', '周婷婷副主任医师，妇科专家。', '子宫肌瘤、宫颈癌、卵巢囊肿', 3100, 4.84, 1800, 1, 80.00, 50.00, 1, '2024-01-01 00:00:00', '2024-01-01 00:00:00');
INSERT IGNORE INTO `t_disease` (`id`, `department_id`, `name`, `description`, `alias`, `location`, `treatment`, `symptoms`, `treatment_period`, `cure_rate`, `examinations`, `follow_count`, `create_time`, `update_time`) VALUES
(1, 11, '高血压', '高血压是指以体循环动脉血压增高为主要特征，可伴有心、脑、肾等器官的功能或器质性损害的临床综合征。', '血压高', '全身', '药物治疗、生活方式干预', '头痛、头晕、心悸、耳鸣', '长期', '85%', '血压测量、心电图、血常规', 12500, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(2, 15, '糖尿病', '糖尿病是一组以高血糖为特征的代谢性疾病，由于胰岛素分泌缺陷或生物作用受损引起。', '消渴病', '全身', '胰岛素治疗、口服降糖药、饮食控制', '多饮、多食、多尿、体重减轻', '长期', '70%', '血糖检测、糖化血红蛋白、尿常规', 9800, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(3, 11, '冠心病', '冠状动脉粥样硬化性心脏病，冠状动脉血管发生动脉粥样硬化病变而引起血管腔狭窄或阻塞。', '冠状动脉疾病', '心脏', '药物治疗、介入治疗、手术治疗', '胸痛、胸闷、心悸、呼吸困难', '长期', '60%', '心电图、冠脉CT、冠脉造影', 8200, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(4, 12, '哮喘', '哮喘是一种气道慢性炎症性疾病，由多种细胞和细胞组分参与，出现广泛而多变的可逆性气流受限。', '支气管哮喘', '呼吸道', '吸入糖皮质激素、支气管舒张剂', '喘息、气急、胸闷、咳嗽', '长期', '80%', '肺功能检查、过敏原检测', 6500, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(5, 13, '胃溃疡', '胃溃疡是位于贲门至幽门之间的慢性溃疡，是消化性溃疡的一种。', '胃溃', '胃部', '抑酸药、胃黏膜保护剂、手术', '上腹部疼痛、反酸、嗳气', '4-8周', '90%', '胃镜、幽门螺杆菌检测', 5800, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(6, 12, '肺炎', '肺炎是指终末气道、肺泡和肺间质的炎症，可由病原微生物、理化因素、免疫损伤等所致。', '肺部感染', '肺部', '抗生素治疗、对症支持治疗', '发热、咳嗽、咳痰、呼吸困难', '1-2周', '95%', '血常规、胸片、CT', 7200, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(7, 22, '颈椎病', '颈椎病是颈椎间盘退变、骨质增生等压迫或刺激神经根、脊髓、血管等引起的综合征。', '颈椎综合征', '颈部', '物理治疗、药物治疗、手术', '颈肩疼痛、上肢麻木、头晕', '长期', '75%', '颈椎X线、CT、MRI', 11000, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(8, 14, '肾病综合征', '肾病综合征是一组临床综合征，以大量蛋白尿、低蛋白血症、水肿和高脂血症为特征。', '肾病', '肾脏', '糖皮质激素、免疫抑制剂', '水肿、蛋白尿、低蛋白血症', '长期', '65%', '尿常规、肾功能、肾穿刺', 4200, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(9, 16, '白血病', '白血病是一类造血干细胞恶性克隆性疾病，克隆性白血病细胞在骨髓和其他造血组织中大量增殖累积。', '血癌', '骨髓、血液', '化疗、放疗、骨髓移植', '发热、贫血、出血、骨痛', '长期', '50%', '血常规、骨髓穿刺', 3800, '2024-01-01 00:00:00', '2024-01-01 00:00:00'),
(10, 31, '子宫肌瘤', '子宫肌瘤是女性生殖器官中最常见的一种良性肿瘤，由子宫平滑肌细胞增生形成。', '子宫平滑肌瘤', '子宫', '药物治疗、手术切除', '月经异常、腹部肿块、白带增多', '短期', '95%', '妇科检查、B超、MRI', 5500, '2024-01-01 00:00:00', '2024-01-01 00:00:00');